        for x2d, y2d in dirs:
            x2, y2 = nx + x2d, ny + y2d
            if inside(x2, y2):
                avail += 1

        score = (10 * s_gain) + (2 if (d < sd0 and d <= od0) else 0) + (0.1 * avail) - (0.01 * d)
        if score > best_score:
            best_score = score
            best_move = (dx, dy)

    return [int(best_move[0]), int(best_move[1])]
